var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"<color=#ffd34c>에스테로사 드 슈발리에.</color>","JPN":"<color=#ffd34c>エステロサ・ド・シュヴァリエ。</color>","ENG":"<color=#ffd34c>Esterosa de Chevalier.</color>","TWN":"<color=#ffd34c>聖騎士艾斯特洛索</color>"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"지금부터, 그녀의 <color=#ffd34c>기사단장직 박탈</color>에 관한 회의를 시작한다.","JPN":"これより、彼女の<color=#ffd34c>騎士団長職剥奪</color>に関する会議を始める。","ENG":"We will now begin deliberation on the <color=#ffd34c>dismissal of her position as Knight Captain</color>.","TWN":"現在開始，關於她的<color=#ffd34c>騎士團長職務剝奪</color>的會議。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐. 그게 대체 무슨 말씀이십니까, 프레이더 경!","JPN":"待ってください、どういうことですか、フレイダー卿！","ENG":"Wait. What are you saying, Sir Frayder?!","TWN":"等一下。那到底是什麼意思，弗雷德！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그래. 기사단장직 박탈이라는 게 대체 무슨 소리야?","JPN":"そ、そうだよ。騎士団長職剥奪って、どういうこと？","ENG":"Y-yeah! What's this about removing her as captain?","TWN":"被剝奪騎士團長職務到底是什麼意思？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임에 참전한 건 우리 선택이었어. 책임을 묻는다면 연대책임이라고!","JPN":"クリフォトゲームに参戦したのは私たちの選択だった。責任を問うとしたら連帯責任だよ！","ENG":"We joined the Qliphoth Game of our own accord. If there's blame to place, it's on all of us!","TWN":"參與逆卡巴拉遊戲是我們的選擇。如果要追究責任，那就是連帶責任！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"리브 경. 기사들의 부덕함을 다스리는 것 또한 단장으로서의 역할이네.","JPN":"リブ卿。騎士たちの不徳を正すこともまた、団長としての務めだ。","ENG":"Dame Liv, upholding the discipline of the knights is also part of a captain's duty.","TWN":"莉芙。管理騎士們的不端行為也是作為團長的職責。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 그래도 이건 너무 갑작스럽잖아!","JPN":"でもこれはいきなりすぎるよ！","ENG":"Still, this is way too sudden!","TWN":"不，這也太突然了吧！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리, 리브 언니. 주변 시선이 이상해요…….","JPN":"リ、リブさん。周りの視線が変です……","ENG":"L-Liv... People are staring...","TWN":"莉，莉芙姊姊。周圍的目光有些奇怪……"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……당했군요. 해당 안건이 대두된 것만으로도 상황은 저희에게 불리하게 작용됩니다.","JPN":"……やられましたね。この案件が取り上げられたという事実だけでも、状況は私たちにとって不利に働きます。","ENG":"...They got us. The moment this motion was raised, the situation turned against us.","TWN":"……被算計了。僅僅是這個議題被提出來，情況就對我們不利。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 버밍엄 교수와 각별한 사이셨으니, 현 상황을 기점으로 의구심을 품는 기사들이 늘어나겠죠.","JPN":"団長がバーミンガム教授と格別な仲だった分、現状況をもって疑いを抱く騎士は増えるでしょう。","ENG":"Given her close ties with Professor Birmingham, this will only fuel doubt among the knights.","TWN":"團長你與伯明罕教授關係密切，現狀可能會引發更多懷疑的報導。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그럼 이제 어떡하죠?","JPN":"じゃ、じゃあこれからどうすれば？","ENG":"Th-then what do we do now?","TWN":"那，那現在怎麼辦？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……한 가지. 묻고 싶은 게 있습니다, 프레이더 경.","JPN":"……1つ、お尋ねしたいことがあります。フレイダー卿。","ENG":"...One question, Sir Frayder.","TWN":"……有一件事。我想問一下，弗雷德。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"원로원은 저희들의 판단이 잘못되었다 생각하십니까?","JPN":"元老院は私たちの判断が間違っていたとお考えですか？","ENG":"Does the Council believe our judgment was wrong?","TWN":"元老院認為我們的判斷是錯誤的嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"통제되지 않는 검의 위험성은 이미 레드시프트로 인해 통감되었네.","JPN":"統制の利かない剣の危険性は、すでにレッドシフトの件で痛感している。","ENG":"We've already seen the dangers of unchecked blades. Red Shift taught us that well.","TWN":"不受控制的劍的危險性已經通過紅移深刻感受到了。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"관리국과 원로원의 지시를 동시에 저버리는 순간, 자네도 나름의 각오를 했겠지.","JPN":"管理局と元老院の指示を同時に無視した瞬間、君もそれなりの覚悟はしただろう。","ENG":"When you defied both the Administration and the Council's orders, I assume you knew what that meant.","TWN":"當你同時違背管理局和元老院的指示時，你也做好了自己的覺悟吧。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"누군가를 구하는 행위를 망설이지 말게.","JPN":"誰かを救うことを躊躇うな。","ENG":"Never hesitate to save someone.","TWN":"切勿猶豫去做拯救他人的事。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그로 인해 책임을 져야 할 순간이 올지라도, 그건 결코 잘못된 행동이 아니야.","JPN":"そのことで責任を問われることになろうとも、それは決して間違った行動ではない。","ENG":"Even if it brings consequences, that alone is never the wrong choice.","TWN":"即便因此需要承擔責任，那也絕不是錯誤的行為。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……わかりました。","ENG":"...Understood.","TWN":"……我知道了。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그게 원로원의 판단이라면 따르겠습니다.","JPN":"それが元老院の判断であるなら、従います。","ENG":"If that is the Council's judgment, I will abide by it.","TWN":"如果那是元老院的決定，我會遵從。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 그게 무슨 말씀이십니까!?","JPN":"団長、どういうことですか？","ENG":"Captain, what are you saying?!","TWN":"團長，你在說什麼啊！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 전통에 예외란 없네, 부단장.","JPN":"騎士団の伝統に例外はない、副団長。","ENG":"There are no exceptions in the Order's traditions, Deputy.","TWN":"騎士團的傳統沒有例外，副團長。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"달리 사태를 수습할 방법이 없다는 걸 그대도 알고 있지 않나.","JPN":"事態を収拾できる方法が他にないということぐらい、君も知っているだろう。","ENG":"You know there's no other way to resolve this.","TWN":"你也知道沒有其他辦法來解決這個問題吧。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"그 말 대로다. 원로원의 판단이 선 이상 해당 안건의 결정을 늦출 필요는 없지.","JPN":"その通りだ。元老院の判断が下されたのなら、これ以上決定を躊躇う必要はない。","ENG":"She's right. Since the Council has already ruled, there's no point delaying the decision.","TWN":"正如你所說，既然元老院已經做出了判斷，就沒有必要推遲該議案的決定。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};